import com.roncoo.education.common.core.tools.DocUtil;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.ByteArrayInputStream;
import java.io.InputStream;

import static org.junit.jupiter.api.Assertions.assertEquals;

class DocUtilTest {

    @Test
    void shouldReturnOneForTxtFile() {
        String fileName = "file.txt";
        InputStream is = new ByteArrayInputStream("test".getBytes());

        int pageCount = DocUtil.getDocPageCount(fileName, is);

        assertEquals(1, pageCount);
    }

    @Test
    void shouldReturnZeroForNullInputStream() {
        String fileName = "file.txt";
        InputStream is = null;

        int pageCount = DocUtil.getDocPageCount(fileName, is);

        assertEquals(0, pageCount);
    }

    @Test
    void shouldReturnZeroForUnsupportedFileType() {
        String fileName = "file.unsupported";
        InputStream is = new ByteArrayInputStream("test".getBytes());

        int pageCount = DocUtil.getDocPageCount(fileName, is);

        assertEquals(0, pageCount);
    }

    @Test
    void shouldReturnZeroWhenExceptionOccurs() {
        String fileName = "file.pdf";
        InputStream is = Mockito.mock(InputStream.class);
        Mockito.doThrow(new RuntimeException()).when(is).read();

        int pageCount = DocUtil.getDocPageCount(fileName, is);

        assertEquals(0, pageCount);
    }
}

