import com.xxl.job.admin.controller.interceptor.CookieInterceptor;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockHttpServletResponse;
import org.springframework.web.servlet.ModelAndView;

import javax.servlet.http.Cookie;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;

public class CookieInterceptorTest {

    @Mock
    private CookieInterceptor cookieInterceptor;

    private MockHttpServletRequest request;
    private MockHttpServletResponse response;
    private ModelAndView modelAndView;

    @BeforeEach
    public void setUp() {
        MockitoAnnotations.initMocks(this);
        request = new MockHttpServletRequest();
        response = new MockHttpServletResponse();
        modelAndView = new ModelAndView();
    }

    @Test
    public void cookiesAreAddedToModelWhenPresent() throws Exception {
        Cookie testCookie = new Cookie("testCookie", "testValue");
        request.setCookies(testCookie);

        cookieInterceptor.postHandle(request, response, new Object(), modelAndView);

        assertNotNull(modelAndView.getModel().get("cookieMap"));
        assertEquals(testCookie, ((Map<String, Cookie>) modelAndView.getModel().get("cookieMap")).get("testCookie"));
    }

    @Test
    public void cookiesAreNotAddedToModelWhenNotPresent() throws Exception {
        cookieInterceptor.postHandle(request, response, new Object(), modelAndView);

        assertNull(modelAndView.getModel().get("cookieMap"));
    }

    @Test
    public void staticMethodIsAddedToModel() throws Exception {
        cookieInterceptor.postHandle(request, response, new Object(), modelAndView);

        assertNotNull(modelAndView.getModel().get("I18nUtil"));
    }
}

