import com.xxl.job.admin.core.util.LocalCacheUtil;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

class LocalCacheUtilTest {

    @BeforeEach
    void setUp() {
        LocalCacheUtil.cleanTimeoutCache();
    }

    @Test
    void setAndGetValidCache() {
        String key = "testKey";
        String value = "testValue";
        long cacheTime = 5000L;

        assertTrue(LocalCacheUtil.set(key, value, cacheTime));
        assertEquals(value, LocalCacheUtil.get(key));
    }

    @Test
    void setAndGetExpiredCache() throws InterruptedException {
        String key = "testKey";
        String value = "testValue";
        long cacheTime = 1L;

        assertTrue(LocalCacheUtil.set(key, value, cacheTime));
        Thread.sleep(2);
        assertNull(LocalCacheUtil.get(key));
    }

    @Test
    void setAndGetNullKey() {
        String key = null;
        String value = "testValue";
        long cacheTime = 5000L;

        assertFalse(LocalCacheUtil.set(key, value, cacheTime));
        assertNull(LocalCacheUtil.get(key));
    }

    @Test
    void setAndGetEmptyKey() {
        String key = "";
        String value = "testValue";
        long cacheTime = 5000L;

        assertFalse(LocalCacheUtil.set(key, value, cacheTime));
        assertNull(LocalCacheUtil.get(key));
    }

    @Test
    void removeExistingKey() {
        String key = "testKey";
        String value = "testValue";
        long cacheTime = 5000L;

        assertTrue(LocalCacheUtil.set(key, value, cacheTime));
        assertTrue(LocalCacheUtil.remove(key));
        assertNull(LocalCacheUtil.get(key));
    }

    @Test
    void removeNonExistingKey() {
        String key = "testKey";

        assertFalse(LocalCacheUtil.remove(key));
    }

    @Test
    void removeNullKey() {
        String key = null;

        assertFalse(LocalCacheUtil.remove(key));
    }

    @Test
    void removeEmptyKey() {
        String key = "";

        assertFalse(LocalCacheUtil.remove(key));
    }
}

